using System;
using System.Collections.Generic;
using System.Linq;
using Chronos.Core;
using Newtonsoft.Json;
using NodaTime;
using ZES.Interfaces.Clocks;

namespace Chronos.Accounts.Queries
{
  public class AccountStats
  {
    public AccountStats() 
    {
    }  
    public Chronos.Core.Quantity Balance
    {
       get; 
       set;
    }  
    public List<Quantity> Positions { get; set; }
    public List<Quantity> Values { get; set; }
    public List<Quantity> Dividends { get; set; }
    public List<Quantity> CostBasis { get; set; }
    public List<Quantity> RealisedGains { get; set; }
    public Quantity CashBalance { get; set; }
    public Quantity TotalDividend { get; set; }
   
    [JsonIgnore]
    public Dictionary<Asset, Dictionary<int, Quantity>> RealisedGainsPerTaxYear { get; set; }
    [JsonIgnore]
    public List<(Instant, Quantity)> ExternalCashflows { get; set; }
    [JsonIgnore]
    public Dictionary<Asset, IAssetPools> AssetPools { get; set; }
    [JsonIgnore]
    public AccountStatsState State { get; set; }
    public double Irr { get; set; }

    /// <summary>
    /// Combines the current account statistics with another AccountStats instance,
    /// excluding merging of asset pools, and updates their values accordingly.
    /// </summary>
    /// <param name="other">The other AccountStats instance to combine with.</param>
    /// <param name="time">The time context for the combination operation.</param>
    /// <exception cref="ArgumentException">
    /// Thrown if the denominators of balances in the two AccountStats instances are different.
    /// </exception>
    public void CombineWithExcludingAssetPools(AccountStats other, Time time)
    {
      if(Balance.Denominator != other.Balance.Denominator)
        throw new ArgumentException("Cannot combine accounts with different denominators");
      
      var assets = Positions.Select(s => s.Denominator);
      var otherAssets = other.Positions.Select(s => s.Denominator);
      var allAssets = assets.Union(otherAssets);

      var positions = new List<Quantity>();
      var values = new List<Quantity>();
      var dividends = new List<Quantity>();
      var assetPools = new Dictionary<Asset, IAssetPools>();
      
      Balance += other.Balance;
      CashBalance += other.CashBalance;
      TotalDividend += other.TotalDividend;
     
      ExternalCashflows.AddRange(other.ExternalCashflows);
      ExternalCashflows = ExternalCashflows.OrderBy(x => x.Item1).ToList();
      
      foreach (var asset in allAssets)
      {
        var thisIndex = Positions.FindIndex(p => p.Denominator == asset);
        var otherIndex = other.Positions.FindIndex(p => p.Denominator == asset);
        
        var thisPosition = thisIndex >= 0 ? Positions[thisIndex] : new Quantity(0, asset);
        var otherPosition = otherIndex >= 0 ? other.Positions[otherIndex] : new Quantity(0, asset);
        positions.Add(thisPosition + otherPosition);

        var thisValue = thisIndex >= 0 ? Values[thisIndex] : new Quantity(0, asset);
        var otherValue = otherIndex >= 0 ? other.Values[otherIndex] : new Quantity(0, asset);
        values.Add(thisValue + otherValue);
        
        var thisDividends = thisIndex >= 0 ? Dividends[thisIndex] : new Quantity(0, asset);
        var otherDividends = otherIndex >= 0 ? other.Dividends[otherIndex] : new Quantity(0, asset);
        dividends.Add(thisDividends + otherDividends);
      }
      
      Positions = positions;
      Values = values;
      Dividends = dividends;
      AssetPools = assetPools;
    }
    
    public AccountStats(Quantity balance)
    {
      Balance = balance;
    }
  }
}

